const tx = $items('Create Transaction')[0].json;
const input = $items('Set Manual Active Call')[0].json;
const normalizedQuery = `search_query: ${tx.user_query.replace(/\s+/g, ' ').trim()}`;
const now = Date.now();
return [{ json: {
  ...tx,
  qdrant_collection: input.qdrant_collection,
  embedding_url: input.embedding_url,
  qdrant_base_url: input.qdrant_base_url,
  gemini_url: input.gemini_url,
  discord_webhook_url: input.discord_webhook_url,
  top_k: Number(input.top_k ?? 20),
  context_k: Number(input.context_k ?? 5),
  min_result_count: Number(input.min_result_count ?? 3),
  retrieval_score_threshold: Number(input.retrieval_score_threshold ?? 0.55),
  normalized_query: normalizedQuery,
  workflow_started_ms: now,
  query_hash: Buffer.from(normalizedQuery).toString('base64').slice(0, 24)
}}];

const state = $items('Prepare Embedding Request')[0].json;
const response = $json;
const body = response.body ?? response;
const vector = body.embedding || body.vector || body.data?.[0]?.embedding || [];
const now = Date.now();
return [{ json: {
  ...state,
  embedding_completed_ms: now,
  embedding_latency_ms: Math.max(0, now - state.embedding_started_ms),
  embedding_status_code: response.statusCode ?? response.status ?? 0,
  query_vector: vector,
  embedding_ok: Array.isArray(vector) && vector.length === 768
}}];

const base = $items('Prepare Qdrant Search')[0].json;
const response = $json;
const now = Date.now();
const statusCode = response.statusCode ?? response.status ?? 0;
const raw = response.body?.result || response.result || [];
const candidates = Array.isArray(raw) ? raw.map((hit, i) => {
  const p = hit.payload || {};
  return {
    qdrant_point_id: String(hit.id),
    rank: i + 1,
    retrieval_score: Number(hit.score || 0),
    channel_id: p.channel_id || '',
    channel_name: p.channel || '',
    thread_name: p.thread_name || '',
    first_message_id: p.first_message_id || '',
    message_ids: Array.isArray(p.message_ids) ? p.message_ids.map(String) : [],
    start_ts: p.start_ts || null,
    end_ts: p.end_ts || null,
    text: p.text || '',
    payload: p
  };
}) : [];
const passed = candidates.filter(c => c.retrieval_score >= base.retrieval_score_threshold);
const selected = passed.slice(0, base.context_k);
let refusalReason = null;
if (!base.embedding_ok) refusalReason = 'query_embedding_failed';
else if (statusCode < 200 || statusCode >= 300) refusalReason = 'qdrant_query_failed';
else if (candidates.length === 0) refusalReason = 'no_qdrant_results';
else if (passed.length < base.min_result_count) refusalReason = 'fewer_than_min_results';
const shouldGenerate = !refusalReason;
const guildId = '853099205206999050';
const contextBlock = selected.map((c, idx) => {
  const dateStart = c.start_ts ? String(c.start_ts).slice(0, 10) : 'unknown';
  const dateEnd = c.end_ts ? String(c.end_ts).slice(0, 10) : 'unknown';
  const link = c.channel_id && c.first_message_id ? `https://discord.com/channels/${guildId}/${c.channel_id}/${c.first_message_id}` : 'N/A';
  const authors = Array.isArray(c.payload.authors) ? c.payload.authors.join(', ') : 'N/A';
  return `--- Context chunk ${idx + 1} of ${selected.length} ---\nChannel:      #${c.channel_name || 'unknown'}\nThread:       ${c.thread_name || 'N/A'}\nDate range:   ${dateStart} to ${dateEnd}\nAuthors:      ${authors}\nScore:        ${c.retrieval_score.toFixed(2)}\nMessage IDs:  ${c.message_ids.join(', ')}\nDiscord link: ${link}\n\n${c.text}`;
}).join('\n\n');
const refusalText = "I don't have enough TPM Unite specific context to answer this confidently, try rephrasing or ask the community directly.";
const systemPrompt = `You are an assistant for the TPM Unite Discord community.\nYou have access to retrieved excerpts from real TPM Unite conversations spanning the community's history.\n\nRULES - follow exactly, in priority order:\n1. GROUNDING: Answer ONLY from the provided context blocks. Never use general knowledge, personal opinions, or external sources. Every claim must be traceable to a specific context block.\n2. REFUSAL: If the provided context is insufficient to answer confidently, respond with exactly: "${refusalText}" Then stop. Do not add caveats, partial answers, or suggestions.\n3. CITATION: After each key claim, cite the source in this format: (#{channel}, {YYYY-MM-DD}). For forum threads: (#{channel} > {thread_name}, {YYYY-MM-DD})\n4. FRAMING: Frame answers as community wisdom, not authoritative rulings. Use language like "TPM Unite members have discussed...", "The community has shared...", "Past discussions suggest..." Never say "You should..." or "The answer is..."\n5. TEMPORAL HONESTY: If context is older than 12 months, note it.\n6. NUANCE CAVEAT: For subjective, evolving, or role-specific topics, close with: "This reflects past TPM Unite discussions - the community may have more recent or personal context to add."\n7. SAFETY: Do not surface personal identifying information from the context even if present.`;
const prompt = `${systemPrompt}\n\nRetrieved context:\n${contextBlock}\n\nUser question:\n${base.user_query}`;
const retrievalRows = candidates.map(c => ({ qdrant_point_id: c.qdrant_point_id, rank: c.rank, retrieval_score: c.retrieval_score, channel_id: c.channel_id, channel_name: c.channel_name, thread_name: c.thread_name, first_message_id: c.first_message_id, message_ids: c.message_ids, start_ts: c.start_ts, end_ts: c.end_ts, payload: c.payload }));
return [{ json: {
  ...base,
  qdrant_completed_ms: now,
  qdrant_latency_ms: Math.max(0, now - base.qdrant_started_ms),
  qdrant_status_code: statusCode,
  raw_candidate_count: candidates.length,
  passed_candidate_count: passed.length,
  selected_context_count: selected.length,
  candidates,
  selected_context: selected,
  context_block: contextBlock,
  context_token_estimate: Math.ceil(contextBlock.length / 4),
  prompt,
  prompt_hash: Buffer.from(prompt).toString('base64').slice(0, 24),
  retrieval_results_sql_json: JSON.stringify(retrievalRows).replace(/'/g, "''"),
  should_generate: shouldGenerate,
  should_generate_int: shouldGenerate ? 1 : 0,
  refusal_reason: refusalReason,
  retrieval_status: shouldGenerate ? 'context_found' : 'no_context',
  final_status: shouldGenerate ? 'answered' : 'refused',
  refusal_text: refusalText,
  score_source: 'retrieval_score_until_rerank_phase'
}}];

const state = $items('Prepare Gemini Request')[0].json;
const response = $json;
const now = Date.now();
const statusCode = response.statusCode ?? response.status ?? 0;
const body = response.body ?? response;
const text = body.candidates?.[0]?.content?.parts?.map(p => p.text || '').join('\n').trim() || '';
let generationFailed = statusCode < 200 || statusCode >= 300 || !text;
let failureReason = null;
if (generationFailed) {
  if (statusCode === 404) failureReason = 'gemini_model_not_found';
  else if (statusCode === 401 || statusCode === 403) failureReason = 'gemini_auth_failed';
  else if (!text && statusCode >= 200 && statusCode < 300) failureReason = 'gemini_malformed_response';
  else failureReason = 'gemini_api_failed';
}
const isModelRefusal = text === state.refusal_text;
return [{ json: {
  ...state,
  gemini_completed_ms: now,
  gemini_latency_ms: Math.max(0, now - state.gemini_started_ms),
  gemini_status_code: statusCode,
  gemini_response_text: text,
  generation_failed: generationFailed,
  generation_failed_int: generationFailed ? 1 : 0,
  gemini_failure_reason: failureReason,
  model_refusal: isModelRefusal,
  discord_response_text: generationFailed ? '' : text,
  final_status: generationFailed ? 'failed' : (isModelRefusal ? 'refused' : 'answered'),
  retrieval_status: 'context_found',
  refusal_reason: generationFailed ? failureReason : (isModelRefusal ? 'gemini_context_insufficient' : null)
}}];

const state = $items('Prepare Discord Answer')[0].json;
const response = $json;
const now = Date.now();
const statusCode = response.statusCode ?? response.status ?? 0;
const ok = statusCode >= 200 && statusCode < 300;
return [{ json: { ...state, discord_completed_ms: now, discord_latency_ms: Math.max(0, now - state.discord_started_ms), discord_status_code: statusCode, discord_response_message_id: response.body?.id || '', response_status: ok ? 'posted' : 'failed' } }];

const state = $items('Prepare Discord Refusal')[0].json;
const response = $json;
const now = Date.now();
const statusCode = response.statusCode ?? response.status ?? 0;
const ok = statusCode >= 200 && statusCode < 300;
return [{ json: { ...state, final_status: 'refused', retrieval_status: state.retrieval_status, discord_completed_ms: now, discord_latency_ms: Math.max(0, now - state.discord_started_ms), discord_status_code: statusCode, discord_response_message_id: response.body?.id || '', response_status: ok ? 'posted' : 'failed' } }];
